import React, { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const TimbangMuat = () => {
  const navigate = useNavigate();

  const [rfid, setRfid] = useState(null);
  const [truck, setTruck] = useState(null);
  const [loading, setLoading] = useState(false);

  const [form, setForm] = useState({
    itemType: '',
    quantity: '',
    no_palka: '',
    bruto_belawan: '',
    tara_belawan: ''
  });

  const [list, setList] = useState([]);

  // ================= RFID =================
  const fetchRFID = useCallback(async () => {
    try {
      setLoading(true);

      const res = await axios.get('http://localhost:5000/api/rfid/latest');

      if (res.data.truck) {
        setRfid(res.data.truck.truckId);
        setTruck(res.data.truck);
        fetchData(res.data.truck.truckId);
      }

    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (!rfid) fetchRFID();
    }, 2000);

    return () => clearInterval(interval);
  }, [rfid, fetchRFID]);

  // ================= HANDLE FORM =================
  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  // ================= SUBMIT =================
  const handleSubmit = async (e) => {
    e.preventDefault();

    const bruto = Number(form.bruto_belawan);
    const tara = Number(form.tara_belawan);

    const payload = {
      truckId: rfid,
      itemType: form.itemType,
      quantity: Number(form.quantity),
      no_palka: form.no_palka,
      bruto_belawan: bruto,
      tara_belawan: tara,
      netto_belawan: bruto - tara,
      unit: 'Kg',
      status_timbang: 'BRUTO'
    };

    try {
      await axios.post('http://localhost:5000/api/loadings', payload);

      alert("Data berhasil disimpan");

      setForm({
        itemType: '',
        quantity: '',
        no_palka: '',
        bruto_belawan: '',
        tara_belawan: ''
      });

      fetchData(rfid);

    } catch (err) {
      console.error(err);
      alert("Gagal simpan data");
    }
  };

  // ================= FETCH DATA =================
  const fetchData = async (truckId) => {
    try {
      const res = await axios.get(`http://localhost:5000/api/loadings/${truckId}`);
      setList(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  // ================= UI =================
  return (
    <div className="p-8 min-h-screen bg-gradient-to-br from-blue-100 to-white">

      <h1 className="text-3xl font-bold text-center mb-8">
        ⚖️ Timbang Muat Belawan System
      </h1>

      {loading && (
        <div className="flex justify-center">
          <div className="animate-spin w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full"></div>
        </div>
      )}

      {!truck && !loading && (
        <p className="text-center text-gray-600">
          Menunggu RFID...
        </p>
      )}

      {truck && (
        <div className="max-w-6xl mx-auto bg-white p-6 shadow rounded">

          {/* ================= TRUCK INFO ================= */}
          <div className="mb-6 grid grid-cols-2 gap-4">
            <div><b>Truck:</b> {truck.truckId}</div>
            <div><b>Driver:</b> {truck.driver}</div>
            <div><b>Tipe:</b> {truck.truckType}</div>
            <div><b>Tanggal:</b> {truck.date?.split('T')[0]}</div>
          </div>

          {/* ================= FORM ================= */}
          <form onSubmit={handleSubmit} className="grid grid-cols-2 gap-4">

            <input
              name="itemType"
              placeholder="Item"
              value={form.itemType}
              onChange={handleChange}
              className="border p-2"
              required
            />

            <input
              name="quantity"
              type="number"
              placeholder="Qty"
              value={form.quantity}
              onChange={handleChange}
              className="border p-2"
              required
            />

            <input
              name="no_palka"
              placeholder="No Palka"
              value={form.no_palka}
              onChange={handleChange}
              className="border p-2"
              required
            />

            <input
              name="bruto_belawan"
              type="number"
              placeholder="Bruto Belawan"
              value={form.bruto_belawan}
              onChange={handleChange}
              className="border p-2"
              required
            />

            <input
              name="tara_belawan"
              type="number"
              placeholder="Tara Belawan"
              value={form.tara_belawan}
              onChange={handleChange}
              className="border p-2"
              required
            />

            {/* AUTO NETTO PREVIEW */}
            <div className="border p-2 bg-gray-100 flex items-center">
              Netto: {form.bruto_belawan && form.tara_belawan
                ? (Number(form.bruto_belawan) - Number(form.tara_belawan))
                : 0} kg
            </div>

            <div className="col-span-2 flex justify-end gap-4 mt-4">
              <button
                type="button"
                onClick={() => navigate(-1)}
                className="bg-gray-400 text-white px-4 py-2"
              >
                Kembali
              </button>

              <button
                type="submit"
                className="bg-blue-600 text-white px-4 py-2"
              >
                Simpan
              </button>
            </div>

          </form>

          {/* ================= TABLE ================= */}
          <div className="mt-10">
            <h3 className="font-bold mb-3">Riwayat Timbang</h3>

            <table className="w-full border text-sm">
              <thead className="bg-blue-200">
                <tr>
                  <th className="border p-2">Item</th>
                  <th className="border p-2">Qty</th>
                  <th className="border p-2">No Palka</th>
                  <th className="border p-2">Bruto</th>
                  <th className="border p-2">Tara</th>
                  <th className="border p-2">Netto</th>
                  <th className="border p-2">Status</th>
                </tr>
              </thead>

              <tbody>
                {list.map((item, i) => (
                  <tr key={i}>
                    <td className="border p-2">{item.itemType}</td>
                    <td className="border p-2">{item.quantity}</td>
                    <td className="border p-2">{item.no_palka}</td>
                    <td className="border p-2">{item.bruto_belawan}</td>
                    <td className="border p-2">{item.tara_belawan}</td>
                    <td className="border p-2 font-bold">{item.netto_belawan}</td>
                    <td className="border p-2">{item.status_timbang}</td>
                  </tr>
                ))}

                {list.length === 0 && (
                  <tr>
                    <td colSpan="7" className="text-center p-4">
                      Belum ada data
                    </td>
                  </tr>
                )}
              </tbody>

            </table>

          </div>

        </div>
      )}
    </div>
  );
};

export default TimbangMuat;
